/**
 * Pure helper that builds the create/update maps emptyCreate eventually
 * passes to mergeV. Exported so unit tests can exercise the invariants
 * without needing a live Neptune connection.
 *
 * Key invariants:
 *  - t.label only in createMap (Neptune cannot relabel existing vertices).
 *  - INSERTED / INSERTED_LONG only in createMap.
 *  - UPDATED / UPDATED_LONG in both, refreshed on every call.
 *  - CUSTOMER / CLOUD in both so long-lived cross-referenced vertices
 *    don't drift.
 *  - targetProperties supplied by the caller flow into both maps and
 *    override the defaults from event.
 */
export function buildEmptyCreateMaps(
    event: RunEvent,
    targetLabel: string,
    targetProperties: Map<any, any>,
    resourceType: number,
    now: number = Date.now(),
    dt: string = new Date(now).toISOString(),
): { createMap: Map<any, any>; updateMap: Map<any, any> } {
    const createMap = new Map<any, any>();
    createMap.set(t.label, targetLabel);
    createMap.set(DatabaseFields.REGION, event['region']);
    createMap.set(DatabaseFields.CUSTOMER, event['customer']);
    createMap.set(DatabaseFields.ACCOUNTID, event['accountID']);
    createMap.set(DatabaseFields.CLOUD, event['cloud']);
    createMap.set(DatabaseFields.RESOURCETYPE, resourceType);
    createMap.set(DatabaseFields.INSERTED, dt);
    createMap.set(DatabaseFields.INSERTED_LONG, now);
    createMap.set(DatabaseFields.UPDATED, dt);
    createMap.set(DatabaseFields.UPDATED_LONG, now);
    // Caller-supplied properties override the defaults.
    for (const [key, value] of targetProperties.entries()) {
        createMap.set(key, value);
    }

    const updateMap = new Map<any, any>();
    updateMap.set(DatabaseFields.UPDATED, dt);
    updateMap.set(DatabaseFields.UPDATED_LONG, now);
    updateMap.set(DatabaseFields.CUSTOMER, event['customer']);
    updateMap.set(DatabaseFields.CLOUD, event['cloud']);
    for (const [key, value] of targetProperties.entries()) {
        updateMap.set(key, value);
    }

    return { createMap, updateMap };
}

