import { jest } from '@jest/globals';
import gremlin from 'gremlin';
import { buildSaveToNeptuneMaps, buildEmptyCreateMaps } from '../../src/shared/database/neptune-maps.mjs';
import { DatabaseFields, SoteriaStatus } from '../../src/shared/constants/database-fields.constants.js';

const t = gremlin.process.t;

// Deterministic timestamps so assertions are stable.
const NOW = 1775646211247;
const DT = new Date(NOW).toISOString();

function makeEvent(overrides = {}) {
    return {
        region: 'eu-west-1',
        accountID: '679045690091',
        customer: 'cko',
        cloud: 'aws',
        resourceType: 12,
        ...overrides,
    };
}

describe('buildSaveToNeptuneMaps', () => {
    test('INSERTED and INSERTED_LONG are only in createMap (never rewritten on match)', () => {
        const event = makeEvent();
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, new Map(), new Map(), NOW, DT);

        expect(createMap.get(DatabaseFields.INSERTED)).toBe(DT);
        expect(createMap.get(DatabaseFields.INSERTED_LONG)).toBe(NOW);
        expect(updateMap.has(DatabaseFields.INSERTED)).toBe(false);
        expect(updateMap.has(DatabaseFields.INSERTED_LONG)).toBe(false);
    });

    test('UPDATED and UPDATED_LONG are refreshed on both paths', () => {
        const event = makeEvent();
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, new Map(), new Map(), NOW, DT);

        expect(createMap.get(DatabaseFields.UPDATED)).toBe(DT);
        expect(createMap.get(DatabaseFields.UPDATED_LONG)).toBe(NOW);
        expect(updateMap.get(DatabaseFields.UPDATED)).toBe(DT);
        expect(updateMap.get(DatabaseFields.UPDATED_LONG)).toBe(NOW);
    });

    test('CUSTOMER and CLOUD are written on both create and update paths', () => {
        // Regression guard for the bug where 282 cko accounts had customer
        // missing because updateMap never carried it.
        const event = makeEvent();
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, new Map(), new Map(), NOW, DT);

        expect(createMap.get(DatabaseFields.CUSTOMER)).toBe('cko');
        expect(createMap.get(DatabaseFields.CLOUD)).toBe('aws');
        expect(updateMap.get(DatabaseFields.CUSTOMER)).toBe('cko');
        expect(updateMap.get(DatabaseFields.CLOUD)).toBe('aws');
    });

    test('REGION defaults from event when caller did not supply it', () => {
        const event = makeEvent({ region: 'us-east-1' });
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, new Map(), new Map(), NOW, DT);

        expect(createMap.get(DatabaseFields.REGION)).toBe('us-east-1');
        expect(updateMap.get(DatabaseFields.REGION)).toBe('us-east-1');
    });

    test('caller-supplied REGION wins over event on both paths', () => {
        // Regression guard for the bug where saveToNeptune unconditionally
        // overwrote region with event['region'], forcing scanners to
        // temporarily mutate event['region'] to persist cross-region ids.
        const event = makeEvent({ region: 'us-east-1' });
        const createIn = new Map([[DatabaseFields.REGION, 'eu-central-1']]);
        const updateIn = new Map([[DatabaseFields.REGION, 'eu-central-1']]);
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, createIn, updateIn, NOW, DT);

        expect(createMap.get(DatabaseFields.REGION)).toBe('eu-central-1');
        expect(updateMap.get(DatabaseFields.REGION)).toBe('eu-central-1');
    });

    test('caller-supplied ACCOUNTID wins over event on both paths', () => {
        const event = makeEvent({ accountID: '246947710791' });
        const createIn = new Map([[DatabaseFields.ACCOUNTID, '679045690091']]);
        const updateIn = new Map([[DatabaseFields.ACCOUNTID, '679045690091']]);
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, createIn, updateIn, NOW, DT);

        expect(createMap.get(DatabaseFields.ACCOUNTID)).toBe('679045690091');
        expect(updateMap.get(DatabaseFields.ACCOUNTID)).toBe('679045690091');
    });

    test('caller-supplied RESOURCETYPE wins over event on both paths', () => {
        const event = makeEvent({ resourceType: 12 });
        const createIn = new Map([[DatabaseFields.RESOURCETYPE, 4]]);
        const updateIn = new Map([[DatabaseFields.RESOURCETYPE, 4]]);
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, createIn, updateIn, NOW, DT);

        expect(createMap.get(DatabaseFields.RESOURCETYPE)).toBe(4);
        expect(updateMap.get(DatabaseFields.RESOURCETYPE)).toBe(4);
    });

    test('SOTERIA_STATUS is refreshed to ACTIVE on both paths', () => {
        const event = makeEvent();
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, new Map(), new Map(), NOW, DT);

        expect(createMap.get(DatabaseFields.SOTERIA_STATUS)).toBe(SoteriaStatus.ACTIVE);
        expect(updateMap.get(DatabaseFields.SOTERIA_STATUS)).toBe(SoteriaStatus.ACTIVE);
    });

    test('null and undefined values are coerced to empty strings', () => {
        const event = makeEvent();
        const createIn = new Map([['explicit_null', null], ['explicit_undef', undefined]]);
        const { createMap } = buildSaveToNeptuneMaps(event, createIn, new Map(), NOW, DT);

        expect(createMap.get('explicit_null')).toBe('');
        expect(createMap.get('explicit_undef')).toBe('');
    });

    test('caller-supplied arbitrary properties are preserved on both paths', () => {
        const event = makeEvent();
        const createIn = new Map([[t.label, 'account'], ['name', 'cko-org-prod']]);
        const updateIn = new Map([['name', 'cko-org-prod']]);
        const { createMap, updateMap } = buildSaveToNeptuneMaps(event, createIn, updateIn, NOW, DT);

        expect(createMap.get(t.label)).toBe('account');
        expect(createMap.get('name')).toBe('cko-org-prod');
        expect(updateMap.get('name')).toBe('cko-org-prod');
    });
});

describe('buildEmptyCreateMaps', () => {
    test('t.label is only in createMap (Neptune cannot relabel)', () => {
        // Regression guard for the linkNeptune bug where placeholders created
        // with label 'vertex' could never be relabeled by a later saveToNeptune.
        const event = makeEvent();
        const { createMap, updateMap } = buildEmptyCreateMaps(event, 'account', new Map(), 1, NOW, DT);

        expect(createMap.get(t.label)).toBe('account');
        expect(updateMap.has(t.label)).toBe(false);
    });

    test('INSERTED and INSERTED_LONG are only in createMap', () => {
        // Regression guard for the emptyCreate bug where the .property() loop
        // rewrote inserted on every linkNeptune call, making every account
        // look freshly-inserted on every scan.
        const event = makeEvent();
        const { createMap, updateMap } = buildEmptyCreateMaps(event, 'account', new Map(), 1, NOW, DT);

        expect(createMap.get(DatabaseFields.INSERTED)).toBe(DT);
        expect(createMap.get(DatabaseFields.INSERTED_LONG)).toBe(NOW);
        expect(updateMap.has(DatabaseFields.INSERTED)).toBe(false);
        expect(updateMap.has(DatabaseFields.INSERTED_LONG)).toBe(false);
    });

    test('UPDATED and UPDATED_LONG are refreshed on both paths', () => {
        const event = makeEvent();
        const { createMap, updateMap } = buildEmptyCreateMaps(event, 'account', new Map(), 1, NOW, DT);

        expect(createMap.get(DatabaseFields.UPDATED)).toBe(DT);
        expect(createMap.get(DatabaseFields.UPDATED_LONG)).toBe(NOW);
        expect(updateMap.get(DatabaseFields.UPDATED)).toBe(DT);
        expect(updateMap.get(DatabaseFields.UPDATED_LONG)).toBe(NOW);
    });

    test('CUSTOMER and CLOUD are on both paths so long-lived vertices do not drift', () => {
        const event = makeEvent();
        const { createMap, updateMap } = buildEmptyCreateMaps(event, 'account', new Map(), 1, NOW, DT);

        expect(createMap.get(DatabaseFields.CUSTOMER)).toBe('cko');
        expect(createMap.get(DatabaseFields.CLOUD)).toBe('aws');
        expect(updateMap.get(DatabaseFields.CUSTOMER)).toBe('cko');
        expect(updateMap.get(DatabaseFields.CLOUD)).toBe('aws');
    });

    test('caller-supplied targetProperties override defaults on both paths', () => {
        // Regression guard for the vpc-peering and s3 scanners that used to
        // mutate event['region'] temporarily. With the new contract they can
        // just pass the correct region directly.
        const event = makeEvent({ region: 'us-east-1' });
        const props = new Map([[DatabaseFields.REGION, 'eu-west-2']]);
        const { createMap, updateMap } = buildEmptyCreateMaps(event, 'vpc', props, 7, NOW, DT);

        expect(createMap.get(DatabaseFields.REGION)).toBe('eu-west-2');
        expect(updateMap.get(DatabaseFields.REGION)).toBe('eu-west-2');
    });

    test('resourceType is written to createMap', () => {
        const event = makeEvent();
        const { createMap } = buildEmptyCreateMaps(event, 'account', new Map(), 1, NOW, DT);

        expect(createMap.get(DatabaseFields.RESOURCETYPE)).toBe(1);
    });

    test('targetProperties with arbitrary keys flow through to both maps', () => {
        const event = makeEvent();
        const props = new Map([['name', 'my-vpc'], ['customFlag', 'true']]);
        const { createMap, updateMap } = buildEmptyCreateMaps(event, 'vpc', props, 7, NOW, DT);

        expect(createMap.get('name')).toBe('my-vpc');
        expect(createMap.get('customFlag')).toBe('true');
        expect(updateMap.get('name')).toBe('my-vpc');
        expect(updateMap.get('customFlag')).toBe('true');
    });
});

import gremlin from 'gremlin';

const t = gremlin.process.t;

// These field-name literals ARE the wire contract between scanners and
// Neptune. Keeping them inline here (rather than importing DatabaseFields
// from the .ts constants file) means the helpers are a pure-ESM module
// that can be unit-tested without a TS loader. If a field name ever
// changes in database-fields.constants.ts, it has to change here too —
// the unit tests in __tests__/database/neptune-maps.test.js assert on
// these exact field names.
const FIELDS = Object.freeze({
    ACCOUNTID: 'accountID',
    CLOUD: 'cloud',
    CUSTOMER: 'customer',
    INSERTED: 'inserted',
    INSERTED_LONG: 'insertedLong',
    REGION: 'region',
    RESOURCETYPE: 'resourceType',
    SOTERIA_STATUS: 'soteriaStatus',
    UPDATED: 'updated',
    UPDATED_LONG: 'updatedLong',
});
const STATUS_ACTIVE = 'active';

const safeValue = (value) => (value === undefined || value === null) ? '' : value;

/**
 * Pure helper that populates the create/update maps saveToNeptune hands to
 *   mergeV(lookupMap)
 *     .option(onCreate, createMap)
 *     .option(onMatch, updateMap, single)
 *
 * Invariants (covered by unit tests in __tests__/database/neptune-maps.test.js):
 *  - INSERTED / INSERTED_LONG live in createMap only — never rewritten on
 *    subsequent saves for an existing vertex.
 *  - UPDATED / UPDATED_LONG live in both maps and are refreshed on every call.
 *  - CUSTOMER / CLOUD live in both maps so long-lived vertices that only
 *    ever take the match path still get these refreshed.
 *  - REGION / ACCOUNTID / RESOURCETYPE respect caller-supplied values on
 *    both paths — default from event only when the caller didn't set them.
 *  - SOTERIA_STATUS is always refreshed to 'active'.
 */
export function buildSaveToNeptuneMaps(event, createMap, updateMap, now = Date.now(), dt = new Date(now).toISOString()) {
    // Sanitise nulls/undefined to '' in caller-supplied values.
    for (const [key, value] of createMap.entries()) {
        createMap.set(key, safeValue(value));
    }
    for (const [key, value] of updateMap.entries()) {
        updateMap.set(key, safeValue(value));
    }

    // createMap — respect caller-supplied region / accountID / resourceType.
    if (!createMap.has(FIELDS.REGION)) {
        createMap.set(FIELDS.REGION, safeValue(event['region']));
    }
    if (!createMap.has(FIELDS.ACCOUNTID)) {
        createMap.set(FIELDS.ACCOUNTID, safeValue(event[FIELDS.ACCOUNTID]));
    }
    createMap.set(FIELDS.CUSTOMER, safeValue(event['customer']));
    createMap.set(FIELDS.CLOUD, safeValue(event['cloud']));
    if (!createMap.has(FIELDS.RESOURCETYPE)) {
        createMap.set(FIELDS.RESOURCETYPE, safeValue(event[FIELDS.RESOURCETYPE]));
    }

    createMap.set(FIELDS.INSERTED, dt);
    createMap.set(FIELDS.INSERTED_LONG, now);
    createMap.set(FIELDS.UPDATED, dt);
    createMap.set(FIELDS.UPDATED_LONG, now);
    createMap.set(FIELDS.SOTERIA_STATUS, STATUS_ACTIVE);

    // updateMap — same invariants minus the INSERTED* fields.
    if (!updateMap.has(FIELDS.REGION)) {
        updateMap.set(FIELDS.REGION, safeValue(event['region']));
    }
    if (!updateMap.has(FIELDS.ACCOUNTID)) {
        updateMap.set(FIELDS.ACCOUNTID, safeValue(event[FIELDS.ACCOUNTID]));
    }
    if (!updateMap.has(FIELDS.RESOURCETYPE)) {
        updateMap.set(FIELDS.RESOURCETYPE, safeValue(event[FIELDS.RESOURCETYPE]));
    }
    updateMap.set(FIELDS.CUSTOMER, safeValue(event['customer']));
    updateMap.set(FIELDS.CLOUD, safeValue(event['cloud']));
    updateMap.set(FIELDS.UPDATED, dt);
    updateMap.set(FIELDS.UPDATED_LONG, now);
    updateMap.set(FIELDS.SOTERIA_STATUS, STATUS_ACTIVE);

    return { createMap, updateMap };
}

/**
 * Pure helper that builds the create/update maps emptyCreate passes to
 *   mergeV(lookupMap)
 *     .option(onCreate, createMap)
 *     .option(onMatch, updateMap, single)
 *
 * Invariants:
 *  - t.label only in createMap (Neptune cannot relabel existing vertices).
 *  - INSERTED / INSERTED_LONG only in createMap.
 *  - UPDATED / UPDATED_LONG in both, refreshed on every call.
 *  - CUSTOMER / CLOUD in both so long-lived cross-referenced vertices
 *    don't drift.
 *  - targetProperties supplied by the caller flow into both maps and
 *    override the defaults from event.
 */
export function buildEmptyCreateMaps(event, targetLabel, targetProperties, resourceType, now = Date.now(), dt = new Date(now).toISOString()) {
    const createMap = new Map();
    createMap.set(t.label, targetLabel);
    createMap.set(FIELDS.REGION, event['region']);
    createMap.set(FIELDS.CUSTOMER, event['customer']);
    createMap.set(FIELDS.ACCOUNTID, event['accountID']);
    createMap.set(FIELDS.CLOUD, event['cloud']);
    createMap.set(FIELDS.RESOURCETYPE, resourceType);
    createMap.set(FIELDS.INSERTED, dt);
    createMap.set(FIELDS.INSERTED_LONG, now);
    createMap.set(FIELDS.UPDATED, dt);
    createMap.set(FIELDS.UPDATED_LONG, now);
    // Caller-supplied properties override the defaults.
    for (const [key, value] of targetProperties.entries()) {
        createMap.set(key, value);
    }

    const updateMap = new Map();
    updateMap.set(FIELDS.UPDATED, dt);
    updateMap.set(FIELDS.UPDATED_LONG, now);
    updateMap.set(FIELDS.CUSTOMER, event['customer']);
    updateMap.set(FIELDS.CLOUD, event['cloud']);
    for (const [key, value] of targetProperties.entries()) {
        updateMap.set(key, value);
    }

    return { createMap, updateMap };
}

import gremlin from 'gremlin';
import { buildSaveToNeptuneMaps, buildEmptyCreateMaps } from '../../src/shared/database/neptune-maps.mjs';

