    CUSTOMER: 'customer',
    INSERTED: 'inserted',
    INSERTED_LONG: 'insertedLong',
    REGION: 'region',
    RESOURCETYPE: 'resourceType',
    SOTERIA_STATUS: 'soteriaStatus',
    UPDATED: 'updated',
    UPDATED_LONG: 'updatedLong',
});
