const glob = require('glob');

// Get all .mjs files
const files = glob.sync('src/shared/services/scanner/aws-resources/**/*.mjs');

const edges = {};
const edgeLabels = {};
const dynamicExpressions = [];

files.forEach(file => {
    const content = fs.readFileSync(file, 'utf-8');
    const lines = content.split('\n');

    for (let i = 0; i < lines.length; i++) {
        if (lines[i].includes('linkNeptune(')) {
            // Find the line with the actual call start
            let fullMatch = lines[i];
            let j = i;

            // Collect lines until we find a complete call (check for balanced parens)
            while (j < lines.length && (fullMatch.match(/\(/g) || []).length > (fullMatch.match(/\)/g) || []).length) {
                j++;
                fullMatch += '\\n' + lines[j];
            }

            // Extract third argument (edge label)
            const match = fullMatch.match(/linkNeptune\\([^,]+,[^,]+,\\s*([^,]+)/);
            if (match) {
                const labelArg = match[1].trim();

                if (labelArg.startsWith(\"'\") || labelArg.startsWith('\"')) {
                    // String literal
                    const label = labelArg.replace(/['\"]\/\//g, '').trim();
                    edges[label] = (edges[label] || 0) + 1;
